#!/usr/bin/env python3
import base64
from pathlib import Path
print('Writing v5 files...')
Path('frontend').mkdir(exist_ok=True)
Path('backend').mkdir(exist_ok=True)
with open('frontend/index.html','wb') as f: f.write(base64.b64decode(''))
print('✅ frontend/index.html')
with open('backend/main.py','wb') as f: f.write(base64.b64decode(''))
print('✅ backend/main.py')
print()
print('Now run:')
print('  git add .')
print('  git commit -m v5-email-forgot-pin')
print('  git push origin main')
